66: /**
67:  * Possible async results for a check call.
68:  */
69: enum class CheckStatus {
70:   // The request is authorized.
71:   OK,
72:   // The authz service could not be queried.
73:   Error,
74:   // The request is denied.
75:   Denied
76: };
