19: void copyHeaderFieldIntoResponse(
20:     ResponsePtr& response,
21:     const Protobuf::RepeatedPtrField<envoy::config::core::v3::HeaderValueOption>& headers) {
22:   for (const auto& header : headers) {
23:     if (header.append().value()) {
24:       response->headers_to_append.emplace_back(header.header().key(), header.header().value());
25:     } else {
26:       response->headers_to_set.emplace_back(header.header().key(), header.header().value());
27:     }
28:   }
29: }
30: 
31: void copyOkResponseMutations(ResponsePtr& response,
32:                              const envoy::service::auth::v3::OkHttpResponse& ok_response) {
33:   copyHeaderFieldIntoResponse(response, ok_response.headers());
34: 
35:   for (const auto& header : ok_response.response_headers_to_add()) {
36:     if (header.has_append()) {
37:       if (header.append().value()) {
38:         response->response_headers_to_add.emplace_back(header.header().key(),
39:                                                        header.header().value());
40:       } else {
41:         response->response_headers_to_set.emplace_back(header.header().key(),
42:                                                        header.header().value());
43:       }
44:     } else {
45:       switch (header.append_action()) {
46:         PANIC_ON_PROTO_ENUM_SENTINEL_VALUES;
47:       case Router::HeaderValueOption::APPEND_IF_EXISTS_OR_ADD:
48:         response->response_headers_to_add.emplace_back(header.header().key(),
49:                                                        header.header().value());
50:         break;
51:       case Router::HeaderValueOption::ADD_IF_ABSENT:
52:         response->response_headers_to_add_if_absent.emplace_back(header.header().key(),
53:                                                                  header.header().value());
54:         break;
55:       case Router::HeaderValueOption::OVERWRITE_IF_EXISTS:
56:         response->response_headers_to_overwrite_if_exists.emplace_back(header.header().key(),
57:                                                                        header.header().value());
58:         break;
59:       case Router::HeaderValueOption::OVERWRITE_IF_EXISTS_OR_ADD:
60:         response->response_headers_to_set.emplace_back(header.header().key(),
61:                                                        header.header().value());
62:         break;
63:       }
64:     }
65:   }
66: 
67:   response->headers_to_remove = std::vector<std::string>{ok_response.headers_to_remove().begin(),
68:                                                          ok_response.headers_to_remove().end()};
69: 
70:   for (const auto& query_parameter : ok_response.query_parameters_to_set()) {
71:     response->query_parameters_to_set.emplace_back(query_parameter.key(), query_parameter.value());
72:   }
73: 
74:   response->query_parameters_to_remove =
75:       std::vector<std::string>{ok_response.query_parameters_to_remove().begin(),
76:                                ok_response.query_parameters_to_remove().end()};
77: }
