101: absl::StatusOr<std::string> validatePathPrefix(absl::string_view path_prefix) {
102:   if (!path_prefix.empty() && path_prefix[0] != '/') {
103:     return absl::InvalidArgumentError("path_prefix should start with \"/\".");
104:   }
105:   return std::string(path_prefix);
106: }
