40:  * Struct definition for all external authorization stats. @see stats_macros.h
41:  */
42: struct InstanceStats {
43:   ALL_TCP_EXT_AUTHZ_STATS(GENERATE_COUNTER_STRUCT, GENERATE_GAUGE_STRUCT)
44: };
